ControlPropertyState.AutoRuleBindingString:
If(
    IsBlank(ddChecklistTemplate_1.Selected),

    Notify(
        "Please select checklist template.",
        NotificationType.Warning
    ),

    Patch(
        tbl_mrl_workorder,
        LookUp(tbl_mrl_workorder, workorder_no = varSelectedWorkOrder.workorder_no),
        {
            form_template: {
                Id: ddChecklistTemplate_1.Selected.ID,
                Value: ddChecklistTemplate_1.Selected.TemplateCode
            }
        }
    );

    Notify("Successfully Saved Checklist Template.", NotificationType.Success);
)

// Update Main Work Order Status
Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder, workorder_no = varSelectedWorkOrder.workorder_no),
    {
        status_workorder_dmp: {
            Id: 9,
            Value: "SUB"
        }
    }
);

Patch(
    tbl_mrl_workorder_log,
    Defaults(tbl_mrl_workorder_log),
    {
        workorder_no_ref: varSelectedWorkOrder.workorder_no,
        workorder_status: "SUB",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);

UpdateContext({isWvatsPopupConfirmSubmit:false});

Notify("Successfully Submit Work Order", NotificationType.Success);
Navigate(WORKORDER_LIST,ScreenTransition.Fade);

Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder, workorder_no = varSelectedWorkOrder.workorder_no),
    {
        status_workorder_dmp: {
            Id: 7,
            Value: "REV1"
        },
        revise_remark_sv: txtReviseRemarksEng.Text

    }
);

Patch(
    tbl_mrl_workorder_log,
    Defaults(tbl_mrl_workorder_log),
    {
        workorder_no_ref: varSelectedWorkOrder.workorder_no,
        workorder_status: "REV1",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);

UpdateContext({isWvatPopupConfirmRevise:false});

Notify("Successfully Reverted Work Order to Supervisor for revision", NotificationType.Success);
Navigate(WORKORDER_LIST,ScreenTransition.Fade);

// 1. Start the loading state
UpdateContext({varIsLoading: true});

// 2. Perform the Refresh
Refresh(tbl_mrl_workorder);

// 3. End the loading state
UpdateContext({varIsLoading: false});

Notify("Data Refreshed", NotificationType.Success)
